@* Interactive component that can toggle theme from anywhere *@
@inject ThemeService ThemeService

<div class="theme-toggle d-flex align-items-center gap-2">
    <span class="theme-indicator" style="color: @ThemeState?.AccentColor;">
        @GetThemeIcon()
    </span>
    <button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme">
        @ThemeState?.Theme
    </button>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? ThemeState { get; set; }

    private async Task CycleTheme()
    {
        var next = ThemeState?.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
        await ThemeService.SetThemeAsync(next);
    }

    private string GetThemeIcon() => ThemeState?.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };
}

@* Shows current theme in the header — works even in static rendering *@

<span class="theme-indicator-header d-flex align-items-center gap-1"
