@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@ThemeState?.Theme" @onchange="OnThemeChanged">
                @foreach (var t in Enum.GetValues<Theme>())
                {
                    <option value="@t">@t</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@ThemeState?.AccentColor"
                       @onchange="OnAccentChanged" />
                <span>@ThemeState?.AccentColor</span>
            </div>
        </div>

        <div class="mt-3 p-3 border rounded" style="border-color: @ThemeState?.AccentColor !important;">
            <strong>Preview:</strong> @ThemeState?.Theme mode with accent
            <span style="color: @ThemeState?.AccentColor;">@ThemeState?.AccentColor</span>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? ThemeState { get; set; }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            await ThemeService.SetThemeAsync(theme);
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString();
        if (!string.IsNullOrEmpty(color))
        {
            await ThemeService.SetAccentColorAsync(color);
        }
    }
}

